-- 0011_book_catalog.sql — каталог библиотеки в D1 + связь автор→личность (FK на entities).
-- Источник: apps/web/src/books.ts (LIBRARY). Закрывает дрейф схемы (см. docs/PASSPORT.md §B).
DROP TABLE IF EXISTS book_catalog;
CREATE TABLE book_catalog (
  id TEXT PRIMARY KEY,
  title TEXT NOT NULL,
  iast TEXT,
  note TEXT,
  author_name TEXT,
  author_entity_id TEXT REFERENCES entities(id),
  lineage TEXT NOT NULL CHECK (lineage IN ('prabhupada','acharya','guru-iskcon')),
  readable INTEGER NOT NULL DEFAULT 0,
  audio INTEGER NOT NULL DEFAULT 0,
  also TEXT,
  sort INTEGER NOT NULL DEFAULT 0
);
CREATE INDEX idx_book_catalog_lineage ON book_catalog(lineage, sort);
CREATE INDEX idx_book_catalog_author ON book_catalog(author_entity_id);
